    def redraw_rectangles(self):
        """Redraw rectangle annotations with proper scaling, zoom, and rotation."""
        self.canvas.delete("rectangle_annotation")  # Clear old rectangles
        if not self.pdf_document:
            return        
        page = self.pdf_document[self.current_page]
        rotation_angle = page.rotation  # Get current page rotation
        for annotation in self.annotations:
            if annotation[0] == "rectangle" and annotation[1] == self.current_page:
                _, page_num, norm_x1, norm_y1, norm_x2, norm_y2, rect_id, fill = annotation
                x1 = norm_x1 * self.page_width
                y1 = norm_y1 * self.page_height
                x2 = norm_x2 * self.page_width
                y2 = norm_y2 * self.page_height
                width = abs(x2 - x1)
                height = abs(y2 - y1)
                print("Before Rotation:", x1, y1, x2, y2, "Width-Height:", width, height)
                if rotation_angle == 90:
                    x1_rotated = self.page_height - y2
                    y1_rotated = x1
                    x2_rotated = x1_rotated + width
                    y2_rotated = y1_rotated + height
                elif rotation_angle == 180:
                    x1_rotated = self.page_width - x2
                    y1_rotated = self.page_height - y2
                    x2_rotated = x1_rotated + width
                    y2_rotated = y1_rotated + height
                elif rotation_angle == 270:
                    x1_rotated = y1
                    y1_rotated = self.page_width - x2
                    x2_rotated = x1_rotated + width
                    y2_rotated = y1_rotated + height
                else:
                    x1_rotated, y1_rotated = x1, y1
                    x2_rotated, y2_rotated = x2, y2
                print("After Rotation:", x1_rotated, y1_rotated, x2_rotated, y2_rotated, 
                    "Width-Height:", abs(x2_rotated - x1_rotated), abs(y2_rotated - y1_rotated))
                outline_color = "red"
                fill_color = "red" if fill else ""
                self.canvas.create_rectangle(
                    x1_rotated, y1_rotated, x2_rotated, y2_rotated,
                    outline=outline_color, fill=fill_color, width=2, tags="rectangle_annotation")
        self.annotation_is_available = True
